using System;
using System.Collections.Generic;
using System.Data.SqlClient;
using System.Net;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.Extensions.Logging;

public class ReportItem
{
    public int ProductId { get; set; }
    public string ProductName { get; set; }
    public string Category { get; set; }
    public decimal Price { get; set; }
    public int StockQuantity { get; set; }
}

public static class FlexibleReportingFunction
{
    [FunctionName("FlexibleReporting")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("SqlDbConnection");
        if (string.IsNullOrEmpty(connectionString))
        {
            log.LogError("SqlDbConnection environment variable not set.");
            return new StatusCodeResult((int)HttpStatusCode.InternalServerError);
        }

        var reportItems = new List<ReportItem>();

        try
        {
            string baseSql = "SELECT ProductId, ProductName, Category, Price, StockQuantity FROM Products WHERE 1=1";
            var whereClauses = new List<string>();

            if (req.Query.ContainsKey("category"))
            {
                string category = req.Query["category"];
                whereClauses.Add($"Category = '{category.Replace("'", "''")}'");
            }

            if (req.Query.ContainsKey("minPrice"))
            {
                if (decimal.TryParse(req.Query["minPrice"], out decimal minPrice))
                {
                    whereClauses.Add($"Price >= {minPrice}");
                }
            }

            if (req.Query.ContainsKey("maxPrice"))
            {
                if (decimal.TryParse(req.Query["maxPrice"], out decimal maxPrice))
                {
                    whereClauses.Add($"Price <= {maxPrice}");
                }
            }

            if (req.Query.ContainsKey("productNameContains"))
            {
                string productNameContains = req.Query["productNameContains"];
                whereClauses.Add($"ProductName LIKE '%{productNameContains.Replace("'", "''")}%'");
            }

            if (req.Query.ContainsKey("minStock"))
            {
                if (int.TryParse(req.Query["minStock"], out int minStock))
                {
                    whereClauses.Add($"StockQuantity >= {minStock}");
                }
            }
            
            if (req.Query.ContainsKey("maxStock"))
            {
                if (int.TryParse(req.Query["maxStock"], out int maxStock))
                {
                    whereClauses.Add($"StockQuantity <= {maxStock}");
                }
            }

            string fullSql = baseSql;
            if (whereClauses.Count > 0)
            {
                fullSql += " AND " + string.Join(" AND ", whereClauses);
            }
            
            using (SqlConnection connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();
                using (SqlCommand command = new SqlCommand(fullSql, connection))
                {
                    using (SqlDataReader reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            reportItems.Add(new ReportItem
                            {
                                ProductId = reader.GetInt32(reader.GetOrdinal("ProductId")),
                                ProductName = reader.GetString(reader.GetOrdinal("ProductName")),
                                Category = reader.GetString(reader.GetOrdinal("Category")),
                                Price = reader.GetDecimal(reader.GetOrdinal("Price")),
                                StockQuantity = reader.GetInt32(reader.GetOrdinal("StockQuantity"))
                            });
                        }
                    }
                }
            }

            return new OkObjectResult(reportItems);
        }
        catch (SqlException ex)
        {
            log.LogError($"SQL Error: {ex.Message}");
            return new StatusCodeResult((int)HttpStatusCode.InternalServerError);
        }
        catch (Exception ex)
        {
            log.LogError($"General Error: {ex.Message}");
